/** WASI binary from fixtures/wanix/hello-repl.wat (regenerate with yarn task run wanix:wasm:build). */
const HELLO_REPL_WASM_HEX =
  ''

function hextobytes(hex: string): Uint8Array {
  const out = new Uint8Array(hex.length / 2)
  for (let i = 0; i < out.length; i++) {
    out[i] = parseInt(hex.slice(i * 2, i * 2 + 2), 16)
  }
  return out
}

export const HELLO_REPL_WASM_BYTES = hextobytes(HELLO_REPL_WASM_HEX)

/** Plain number array for Playwright page.evaluate (structured clone). */
export const HELLO_REPL_WASM_BYTE_LIST = [...HELLO_REPL_WASM_BYTES]

export function createhelloreplwasmfile(): File {
  return new File([new Uint8Array(HELLO_REPL_WASM_BYTES)], 'hello-repl.wasm', {
    type: 'application/wasm',
  })
}
